import time
import json

def enrichir_ioc_batch(ips, api_func, delai=1.0):
    """
    Enrichit une liste d'IPs via une API.
    delai : pause entre chaque requête (respecter les rate limits)
    """
    resultats = {}
    for i, ip in enumerate(ips, 1):
        print(f"[{i}/{len(ips)}] Analyse de {ip}...")
        resultats[ip] = api_func(ip)
        if i < len(ips):
            time.sleep(delai)  # Éviter le rate limiting
    return resultats

# Simuler l'enrichissement (sans API réelle)
def mock_threat_intel(ip):
    score_db = {
        "185.220.101.3": 95,
        "194.165.16.11": 82,
        "10.0.0.1":       0
    }
    return {"score": score_db.get(ip, 10), "source": "mock"}

ips_a_verifier = ["185.220.101.3", "10.0.0.1"]
resultats = enrichir_ioc_batch(ips_a_verifier, mock_threat_intel, delai=0)

for ip, data in resultats.items():
    niveau = "MALVEILLANT" if data["score"] > 50 else "OK"
    print(f"{ip}: {niveau} (score={data['score']})")
